const { getPlanetPosition, PLANETS } = require('./ephemeris');

/**
 * Find the Design date: the moment when the Sun was exactly 88 degrees
 * behind (retrograde) its position at birth.
 *
 * Uses binary search between ~96 and ~84 days before birth.
 * Returns the Julian Day of the design date.
 */
function findDesignDate(birthJulianDay) {
  const birthSunLong = getPlanetPosition(birthJulianDay, PLANETS.Sun).longitude;

  let low = birthJulianDay - 96;
  let high = birthJulianDay - 84;

  const TARGET = 88.0;
  const TOLERANCE = 0.00001;
  const MAX_ITERATIONS = 100;

  for (let i = 0; i < MAX_ITERATIONS; i++) {
    const mid = (low + high) / 2;
    const midSunLong = getPlanetPosition(mid, PLANETS.Sun).longitude;

    let diff = Math.abs(birthSunLong - midSunLong);
    if (diff > 180) diff = 360 - diff;

    if (diff > TARGET - TOLERANCE && diff < TARGET + TOLERANCE) {
      return mid;
    }

    if (diff > TARGET) {
      low = mid;   // too far back, move forward
    } else {
      high = mid;  // not far enough, move further back
    }
  }

  throw new Error('Failed to find design date within max iterations');
}

module.exports = { findDesignDate };
